mapper.select:
select r.id as registrationId, u.id as userId, u.username as username, u.real_name as realName, u.phone as phone, u.email as email, a.id as activityId, a.title as activityTitle, a.status as activityStatus, r.status as registrationStatus, r.remark as remark, r.audit_user_id as auditUserId, au.username as auditUsername, r.audit_time as auditTime, r.create_time as registrationTime, r.update_time as updateTime from registration r left join `user` u on r.user_id = u.id left join activity a on r.activity_id = a.id left join `user` au on r.audit_user_id = au.id
and r.status = #{status}
and r.activity_id = #{activityId}
and ( u.username like concat('%', #{keyword}, '%') or u.real_name like concat('%', #{keyword}, '%') or u.phone like concat('%', #{keyword}, '%') or a.title like concat('%', #{keyword}, '%') )
order by r.create_time desc
